class StockPrice:

    def __init__(self):
        self.timestamp_price = {}
        self.max_heap = []
        self.min_heap = []

    def update(self, timestamp: int, price: int) -> None:
        self.timestamp_price[timestamp] = price
        heapq.heappush(self.max_heap, -price)
        heapq.heappush(self.min_heap, price)

    def current(self) -> int:
        return self.timestamp_price[max(self.timestamp_price)]

    def maximum(self) -> int:
        max_price = -self.max_heap[0]
        while -self.max_heap[0] not in self.timestamp_price.values():
            heapq.heappop(self.max_heap)
        return max_price

    def minimum(self) -> int:
        min_price = self.min_heap[0]
        while self.min_heap[0] not in self.timestamp_price.values():
            heapq.heappop(self.min_heap)
        return min_price
